static int shadow_quality = 1;
static const char* quality_items = "منخفض\0متوسط\0عالٍ\0فائق\0";
static const char* quality_label = "متوسط";

if (ImGui::Begin("إعدادات الرسم")) {
 if (ImGui::Combo("جودة الظلال", &shadow_quality, quality_items)) {
 quality_label = shadow_quality == 0 ? "منخفض" : (shadow_quality == 1 ? "متوسط" : (shadow_quality == 2 ? "عالٍ" : "فائق"));
 }

 ImGui::Text("الاختيار الحالي: %s", quality_label);
}
ImGui::End();
